/**
 * generate-products.mjs
 *
 * Scans public/products/ — each subfolder is one product.
 * Each folder must contain:
 *   - info.json  (name, price, description, category)
 *   - one or more images (jpg, jpeg, png, webp)
 *
 * Outputs: src/data/products.ts (auto-generated, do not edit manually)
 */

import fs from 'fs'
import path from 'path'

const PRODUCTS_DIR = path.resolve('public/products')
const OUTPUT_FILE  = path.resolve('src/data/products.ts')
const BASE_PATH    = '/tokma-bakery/products'
const IMAGE_EXTS   = ['.jpg', '.jpeg', '.png', '.webp']

const VALID_CATEGORIES = ['cake', 'bread', 'pastry', 'cookies', 'traditional']
const VALID_STATUSES   = ['available', 'coming_soon', 'out_of_stock']

// ── Read all product folders ───────────────────────────────────────────────────
if (!fs.existsSync(PRODUCTS_DIR)) {
  fs.mkdirSync(PRODUCTS_DIR, { recursive: true })
  console.log('📁 Created public/products/ folder.')
}

const folders = fs.readdirSync(PRODUCTS_DIR)
  .filter(name => fs.statSync(path.join(PRODUCTS_DIR, name)).isDirectory())
  .sort((a, b) => a.localeCompare(b, undefined, { numeric: true, sensitivity: 'base' }))

if (folders.length === 0) {
  console.warn('⚠️  No product folders found in public/products/. Generating empty list.')
}

const products = []
const errors   = []

for (const folder of folders) {
  const folderPath = path.join(PRODUCTS_DIR, folder)
  const infoPath   = path.join(folderPath, 'info.json')

  // ── Validate info.json ───────────────────────────────────────────────────
  if (!fs.existsSync(infoPath)) {
    errors.push(`❌ "${folder}": missing info.json`)
    continue
  }

  let info
  try {
    info = JSON.parse(fs.readFileSync(infoPath, 'utf-8'))
  } catch {
    errors.push(`❌ "${folder}": info.json is not valid JSON`)
    continue
  }

  const { name, price, description, category, featured, limitedEdition, order, options, status } = info

  if (!name || typeof name !== 'string') {
    errors.push(`❌ "${folder}": info.json missing "name"`)
    continue
  }
  if (typeof price !== 'number') {
    errors.push(`❌ "${folder}": info.json missing "price" (must be a number)`)
    continue
  }
  if (!description || typeof description !== 'string') {
    errors.push(`❌ "${folder}": info.json missing "description"`)
    continue
  }
  if (!VALID_CATEGORIES.includes(category)) {
    errors.push(`❌ "${folder}": category must be one of: ${VALID_CATEGORIES.join(', ')}`)
    continue
  }
  if (status && !VALID_STATUSES.includes(status)) {
    errors.push(`❌ "${folder}": status must be one of: ${VALID_STATUSES.join(', ')}`)
    continue
  }

  // ── Collect images (sorted) ──────────────────────────────────────────────
  let images = fs.readdirSync(folderPath)
    .filter(f => IMAGE_EXTS.includes(path.extname(f).toLowerCase()))
    .sort()
    .map(f => `${BASE_PATH}/${folder}/${f}`)

  if (images.length === 0) {
    const placeholder = `https://placehold.co/400x300/E5E7EB/9CA3AF?text=No+Image`
    images = [placeholder]
    console.log(`  ⚠️  No image found for "${folder}" — using placeholder`)
  }

  products.push({
    id: folder, name, price, description, category, images,
    ...(status                    ? { status }               : {}),
    ...(Array.isArray(options) && options.length ? { options } : {}),
    ...(typeof order === 'number' ? { order }               : {}),
    ...(featured                  ? { featured: true }       : {}),
    ...(limitedEdition            ? { limitedEdition: true } : {}),
  })
  console.log(`✅ ${folder} — ${images.length} image(s)`)
}

// ── Report errors ─────────────────────────────────────────────────────────────
if (errors.length > 0) {
  console.error('\nSome products had errors and were skipped:')
  errors.forEach(e => console.error(' ', e))
}

// ── Sort by order field (undefined = end of list) ────────────────────────────
products.sort((a, b) => {
  const aOrder = a.order ?? Infinity
  const bOrder = b.order ?? Infinity
  return aOrder - bOrder
})

// ── Generate products.ts ──────────────────────────────────────────────────────
const lines = [
  `// ⚠️  AUTO-GENERATED by scripts/generate-products.mjs`,
  `// Do not edit this file manually.`,
  `// To add/edit products: edit files in public/products/<item-name>/`,
  ``,
  `import type { Product } from '../types'`,
  ``,
  `export const PRODUCTS: Product[] = ${JSON.stringify(products, null, 2)}`,
  ``,
  `export const CATEGORIES = ['All', 'cake', 'bread', 'pastry', 'cookies', 'traditional'] as const`,
  `export type CategoryFilter = typeof CATEGORIES[number]`,
]

fs.writeFileSync(OUTPUT_FILE, lines.join('\n'), 'utf-8')
console.log(`\n🎉 Generated ${products.length} product(s) → src/data/products.ts`)
